"use client";

import { useState } from "react";
import { Check, Copy } from "lucide-react";

import { Button } from "@/components/ui/button";

const CAREERS_EMAIL = "careers@automataqa.com";

export function QACareersSection() {
  const [copied, setCopied] = useState(false);

  const handleCopyEmail = async () => {
    try {
      await navigator.clipboard.writeText(CAREERS_EMAIL);
      setCopied(true);
      window.setTimeout(() => setCopied(false), 1500);
    } catch {
      setCopied(false);
    }
  };

  return (
    <section id="careers" className="py-16 md:py-20">
      <div className="container">
        <div className="mx-auto max-w-6xl rounded-2xl border border-primary/30 bg-primary/8 p-6 text-center md:p-8">
          <p className="text-xs uppercase tracking-[0.2em] text-muted-foreground">
            Careers at AutomataQA
          </p>
          <h2 className="mx-auto mt-3 max-w-2xl text-2xl font-semibold tracking-tight md:text-4xl">
            We are hiring QA engineers.
          </h2>
          <p className="mx-auto mt-4 max-w-xl text-sm text-muted-foreground md:text-base">
            Join our LATAM QA team and work directly with U.S. product and engineering teams. Own
            quality end-to-end - from test automation and exploratory testing to modern product
            validation across web and mobile.
          </p>
          <div className="mt-6 flex flex-col items-center gap-3">
            <p className="text-sm font-medium text-foreground">Apply to join our team</p>
            <Button
              type="button"
              variant="ghost"
              size="lg"
              className="inline-flex h-auto items-center gap-2 bg-transparent hover:bg-transparent"
              onClick={handleCopyEmail}
            >
              {copied ? <Check className="h-4 w-4" /> : <Copy className="h-4 w-4" />}
              <span>{CAREERS_EMAIL}</span>
            </Button>
          </div>
        </div>
      </div>
    </section>
  );
}
